CREATE INDEX IF NOT EXISTS idx_claims_claimant_id ON claims(claimant_id);
CREATE INDEX IF NOT EXISTS idx_claims_assigned_assessor_id ON claims(assigned_assessor_id);
CREATE INDEX IF NOT EXISTS idx_claims_status ON claims(status);
CREATE INDEX IF NOT EXISTS idx_claims_created_at ON claims(created_at);

-- Add indexes for panel beater quotes
CREATE INDEX IF NOT EXISTS idx_quotes_claim_id ON panel_beater_quotes(claim_id);
CREATE INDEX IF NOT EXISTS idx_quotes_panel_beater_id ON panel_beater_quotes(panel_beater_id);

-- Add indexes for assessor evaluations
CREATE INDEX IF NOT EXISTS idx_evaluations_claim_id ON assessor_evaluations(claim_id);
CREATE INDEX IF NOT EXISTS idx_evaluations_assessor_id ON assessor_evaluations(assessor_id);

-- Add indexes for audit trail
CREATE INDEX IF NOT EXISTS idx_audit_claim_id ON audit_trail(claim_id);
CREATE INDEX IF NOT EXISTS idx_audit_user_id ON audit_trail(user_id);
CREATE INDEX IF NOT EXISTS idx_audit_created_at ON audit_trail(created_at);

-- Add indexes for AI assessments
CREATE INDEX IF NOT EXISTS idx_ai_assessments_claim_id ON ai_assessments(claim_id);

